将外层循环分块，使每个块的行能放入L2/L3缓存。同时重新排列内层循环，对每个块预取x向量元素。

// 分块大小（根据L2缓存调整）
#define BLOCK_SIZE 256
void sparse_matvec_optimized(int n, const int *rowptr, const int *colidx,
                             const double *values, const double *x, double *y) {
    for (int ii = 0; ii < n; ii += BLOCK_SIZE) {
        int i_end = (ii + BLOCK_SIZE < n) ? ii + BLOCK_SIZE : n;
        // 预取当前块需要的x元素
        for (int i = ii; i < i_end; i++) {
            double sum = 0.0;
            for (int j = rowptr[i]; j < rowptr[i+1]; j++) {
                sum += values[j] * x[colidx[j]];
            }
            y[i] = sum;
        }
    }
}

对内层循环进行手动向量化，使用FMA指令。需要处理不规则长度和对齐问题。

#include <immintrin.h>
void sparse_matvec_simd(int n, const int *rowptr, const int *colidx,
                        const double *values, const double *x, double *y) {
    for (int i = 0; i < n; i++) {
        __m256d sum_vec = _mm256_setzero_pd();
        int j = rowptr[i];
        int remainder = (rowptr[i+1] - j) % 4;

        // 向量化部分
        for (; j < rowptr[i+1] - remainder; j += 4) {
            __m256d val_vec = _mm256_loadu_pd(&values[j]);
            // 收集x[colidx[j:j+3]]
            __m256d x_vec = _mm256_set_pd(x[colidx[j+3]], x[colidx[j+2]],
                                          x[colidx[j+1]], x[colidx[j]]);
            sum_vec = _mm256_fmadd_pd(val_vec, x_vec, sum_vec);
        }

        // 标量处理剩余部分
        double sum = sum_vec[0] + sum_vec[1] + sum_vec[2] + sum_vec[3];
        for (int k = 0; k < remainder; k++) {
            sum += values[j+k] * x[colidx[j+k]];
        }
        y[i] = sum;
    }
}

展开循环以减少分支开销，并使用SIMD指令。

double dot_product_optimized(const double *x, const double *y, int n) {
    __m256d sum_vec = _mm256_setzero_pd();
    int i;
    for (i = 0; i < n - 3; i += 4) {
        __m256d x_vec = _mm256_loadu_pd(&x[i]);
        __m256d y_vec = _mm256_loadu_pd(&y[i]);
        sum_vec = _mm256_fmadd_pd(x_vec, y_vec, sum_vec);
    }
    double sum = sum_vec[0] + sum_vec[1] + sum_vec[2] + sum_vec[3];
    // 处理剩余元素
    for (; i < n; i++) {
        sum += x[i] * y[i];
    }
    return sum;
}

